use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type Limits {
  min: Int,
  max: Int,
}

pub type VaultDatum {
  owner: ByteArray,
  limits: Limits,
}

fn total_output_lovelace(outputs: List<Output>, owner_pkh: ByteArray) -> Int {
  list.foldl(
    outputs,
    0,
    fn(output, acc) {
      use cardano/address.{VerificationKey}
      when output.address.payment_credential is {
        VerificationKey(pkh) ->
          if pkh == owner_pkh {
            acc + assets.lovelace_of(output.value)
          } else {
            acc
          }
        _ -> acc
      }
    },
  )
}

validator nested_config {
  spend(
    datum: Option<VaultDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let owner = d.owner
    let min_amount = d.limits.min
    let max_amount = d.limits.max
    let is_signed = list.has(self.extra_signatories, owner)
    let total = total_output_lovelace(self.outputs, owner)
    let within_limits = total >= min_amount && total <= max_amount
    is_signed && within_limits
  }
}

use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{
  InlineDatum, Input, Output, OutputReference, Transaction,
}

pub type PoolDatum {
  reserve_a: Int,
  reserve_b: Int,
  lp_supply: Int,
}

pub type WithdrawRedeemer {
  lp_burn_amount: Int,
  min_receive_a: Int,
  min_receive_b: Int,
}

fn get_pool_datum(output: Output) -> Option<PoolDatum> {
  when output.datum is {
    InlineDatum(raw) -> {
      expect typed: PoolDatum = raw
      Some(typed)
    }
    _ -> None
  }
}

fn find_continuing_output(outputs: List<Output>, own_address: cardano/address.Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_address })
}

validator lp_withdraw(
  lp_policy_id: ByteArray,
  lp_asset_name: ByteArray,
) {
  spend(
    datum: Option<PoolDatum>,
    redeemer: WithdrawRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(pool_datum) = datum

    let lp_burn_amount = redeemer.lp_burn_amount

    // lp_burn_amount must be positive
    let burn_positive = lp_burn_amount > 0

    // lp_supply must be positive
    let supply_positive = pool_datum.lp_supply > 0

    // Calculate proportional share of reserves
    let expected_receive_a =
      pool_datum.reserve_a * lp_burn_amount / pool_datum.lp_supply
    let expected_receive_b =
      pool_datum.reserve_b * lp_burn_amount / pool_datum.lp_supply

    // Minimum receive checks
    let min_a_ok = expected_receive_a >= redeemer.min_receive_a
    let min_b_ok = expected_receive_b >= redeemer.min_receive_b

    // Verify the minted/burned value contains the correct LP burn amount
    // Burn is represented as negative mint
    let burned_lp =
      assets.quantity_of(self.mint, lp_policy_id, lp_asset_name)
    let burn_matches = burned_lp == -lp_burn_amount

    // Find the continuing pool output (same address as the input being spent)
    let own_input =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })

    let pool_continues =
      when own_input is {
        Some(input) -> {
          let own_address = input.output.address
          when
            list.find(self.outputs, fn(o) { o.address == own_address })
          is {
            Some(cont_out) ->
              when cont_out.datum is {
                InlineDatum(raw) -> {
                  expect new_pool: PoolDatum = raw

                  // New reserves should reflect withdrawal
                  let new_reserve_a_ok =
                    new_pool.reserve_a == pool_datum.reserve_a - expected_receive_a
                  let new_reserve_b_ok =
                    new_pool.reserve_b == pool_datum.reserve_b - expected_receive_b
                  let new_supply_ok =
                    new_pool.lp_supply == pool_datum.lp_supply - lp_burn_amount

                  // New reserves must remain non-negative
                  let reserves_non_negative =
                    new_pool.reserve_a >= 0 && new_pool.reserve_b >= 0

                  new_reserve_a_ok && new_reserve_b_ok && new_supply_ok && reserves_non_negative
                }
                _ -> False
              }
            None -> False
          }
        }
        None -> False
      }

    burn_positive && supply_positive && min_a_ok && min_b_ok && burn_matches && pool_continues
  }

  else(_) {
    False
  }
}

use aiken/interval
