pub type BridgeDatum {
  amount: Int,
  recipient: ByteArray,
  nonce: ByteArray,
}

pub type NonceDatum {
  used_nonces: List<ByteArray>,
}

fn find_reference_nonce_datum(
  reference_inputs: List<Input>,
) -> Option<NonceDatum> {
  let result =
    list.find(
      reference_inputs,
      fn(input) {
        when input.output.datum is {
          InlineDatum(raw) -> {
            let maybe: Option<NonceDatum> =
              if True {
                when raw is {
                  _ -> {
                    expect nd: NonceDatum = raw
                    True
                    nd
                    True
                  }
                }
                True
              } else {
                False
              }
            when maybe is {
              Some(_) -> True
              None -> False
            }
          }
          _ -> False
        }
      },
    )
  when result is {
    Some(input) ->
      when input.output.datum is {
        InlineDatum(raw) -> {
          expect nd: NonceDatum = raw
          Some(nd)
        }
        _ -> None
      }
    None -> None
  }
}

fn check_nonce_unused(
  reference_inputs: List<Input>,
  nonce: ByteArray,
) -> Bool {
  let maybe_nonce_datum = find_reference_nonce_datum(reference_inputs)
  when maybe_nonce_datum is {
    Some(nd) -> !list.has(nd.used_nonces, nonce)
    None -> False
  }
}

fn check_recipient_receives(
  outputs: List<Output>,
  recipient: ByteArray,
  amount: Int,
) -> Bool {
  list.any(
    outputs,
    fn(output) {
      when output.address.payment_credential is {
        _ -> {
          let addr_matches =
            when output.address.payment_credential is {
              aiken/crypto.VerificationKey(pkh) -> pkh == recipient
              _ -> False
            }
          let lovelace = assets.lovelace_of(output.value)
          addr_matches && lovelace >= amount
        }
      }
    },
  )
}

validator bridge_release {
  spend(
    datum: Option<BridgeDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let nonce_unused =
      check_nonce_unused(self.reference_inputs, d.nonce)

    let recipient_paid =
      list.any(
        self.outputs,
        fn(output) {
          let lovelace = assets.lovelace_of(output.value)
          lovelace >= d.amount
        },
      )

    nonce_unused && recipient_paid
  }
}

