      }

    recipient_signed && fee_check
  }
}

use aiken/collection/list
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type BatchDatum {
  recipients: List<ByteArray>,
  amounts: List<Int>,
  sender: ByteArray,
}

fn pairs_valid(
  recipients: List<ByteArray>,
  amounts: List<Int>,
  outputs: List<Output>,
) -> Bool {
  when recipients is {
    [] ->
      when amounts is {
        [] -> True
        _ -> False
      }
    [r, ..rest_r] ->
      when amounts is {
        [] -> False
        [a, ..rest_a] -> {
          let found =
            list.any(
              outputs,
              fn(o) {
                when o.address.payment_credential is {
                  cardano/address.VerificationKey(pkh) ->
                    pkh == r && assets.lovelace_of(o.value) >= a
                  _ -> False
                }
              },
            )
          found && pairs_valid(rest_r, rest_a, outputs)
        }
      }
  }
}

validator batch_transfer {
  spend(
    datum: Option<BatchDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let sender_signed = list.has(self.extra_signatories, d.sender)
    let all_pairs_valid =
      pairs_valid(d.recipients, d.amounts, self.outputs)
    sender_signed && all_pairs_valid
  }
}

use aiken/interval
use aiken/collection/list
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type RecurringDatum {
  payer: ByteArray,
  payee: ByteArray,
  amount: Int,
  period_secs: Int,
  last_paid: Int,
}

pub type RecurringRedeemer {
  MakePayment
  Cancel
}

validator recurring_payment {
  spend(
    datum: Option<RecurringDatum>,
    redeemer: RecurringRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      MakePayment -> {
        let deadline = d.last_paid + d.period_secs

        let period_elapsed =
          interval.is_entirely_after(self.validity_range, deadline)

        let payee_receives_enough =
          list.any(
            self.outputs,
            fn(o) {
              when o.datum is {
                _ ->
                  when o.address.payment_credential is {
                    cardano/address.VerificationKey(pkh) ->
                      pkh == d.payee && assets.lovelace_of(o.value) >= d.amount
                    _ -> False
                  }
              }
            },
          )

        let continuing_output_valid =
          list.any(
            self.outputs,
            fn(o) {
              let own_input =
                list.find(
                  self.inputs,
                  fn(i) { i.output_reference == utxo },
                )
              when own_input is {
                Some(inp) ->
                  o.address == inp.output.address && when o.datum is {
                    InlineDatum(raw) -> {
                      expect next: RecurringDatum = raw
                      next.payer == d.payer && next.payee == d.payee && next.amount == d.amount && next.period_secs == d.period_secs && next.last_paid > d.last_paid
                    }
                    _ -> False
                  }
                None -> False
              }
            },
          )

        period_elapsed && payee_receives_enough && continuing_output_valid
      }

      Cancel ->
        list.has(self.extra_signatories, d.payer)
    }
  }
}
